const airtableItems = $input.all();
let webhookData = null;
try { webhookData = $('Invoice Request Webhook').first(); } catch(e) { /* webhook not triggered */ }

const items = [];

// Add Airtable draft invoices
for (const item of airtableItems) {
  if (item.json && item.json['Invoice ID']) {
    items.push(item.json);
  }
}

// Add webhook invoice request if present
if (webhookData && webhookData.json && webhookData.json.body) {
  const body = webhookData.json.body;
  items.push({
    'Invoice ID': `INV-${Date.now()}`,
    'Customer ID': body.customer_id || '',
    'Customer Name': body.customer_name || '',
    'Line Items JSON': JSON.stringify(body.line_items || []),
    'Source': body.source || 'Manual',
    'Status': 'Draft',
    isWebhook: true,
  });
}

if (items.length === 0) {
  return [{json: {totalItems: 0, source: 'none'}}];
}
return items.map(item => ({json: item}));

const invoice = $('Loop Over Invoices').first().json;
const customerData = $input.first().json;

return {
  json: {
    ...invoice,
    customerName: customerData['Customer Name'] || invoice['Customer Name'] || '',
    customerEmail: customerData['Email'] || invoice['Email'] || '',
    customerPhone: customerData['Phone'] || invoice['Phone'] || '',
    preferredChannel: customerData['Preferred Channel'] || 'Email',
    xeroContactId: customerData['Xero Contact ID'] || '',
    customerId: customerData['Customer ID'] || invoice['Customer ID'] || '',
    paymentTerms: customerData['Payment Terms'] || '30 days',
  }
};

const invoice = $input.first().json;
const products = $('Lookup Products').all();
const vatRate = parseFloat($('System Config').first().json.vatRate) || 0.15;

const TAX_TYPE_MAP = {'STANDARD_15': 'OUTPUT2', 'ZERO_RATED': 'OUTPUTZERO', 'EXEMPT': 'EXEMPTOUTPUT'};

const lineItemsRaw = invoice['Line Items JSON'] || invoice.line_items || '[]';
let lineItems;
try {
  lineItems = typeof lineItemsRaw === 'string' ? JSON.parse(lineItemsRaw) : lineItemsRaw;
} catch(e) {
  lineItems = [];
}

let subtotal = 0;
let totalVat = 0;
const processedItems = [];
const xeroLineItems = [];

for (const item of lineItems) {
  const product = products.find(p => p.json['Item Code'] === item.item_code || p.json['Item Code'] === item.code);
  const unitPrice = item.unit_price || (product ? product.json['Unit Price'] : 0);
  const qty = item.quantity || 1;
  const vatCode = item.vat_rate_code || (product ? product.json['VAT Rate Code'] : 'STANDARD_15');
  const taxType = TAX_TYPE_MAP[vatCode] || 'OUTPUT2';

  const lineSubtotal = unitPrice * qty;
  const lineVatRate = vatCode === 'STANDARD_15' ? vatRate : 0;
  const lineVat = lineSubtotal * lineVatRate;

  subtotal += lineSubtotal;
  totalVat += lineVat;

  processedItems.push({
    item_code: item.item_code || item.code,
    description: item.description || (product ? product.json['Description'] : ''),
    quantity: qty,
    unit_price: unitPrice,
    vat_rate_code: vatCode,
    vat_rate: lineVatRate,
    line_subtotal: lineSubtotal,
    line_vat: lineVat,
    line_total: lineSubtotal + lineVat,
  });

  xeroLineItems.push({
    ItemCode: item.item_code || item.code || (product ? product.json['Item Code'] : ''),
    Description: item.description || (product ? product.json['Description'] : ''),
    Quantity: qty,
    UnitAmount: unitPrice,
    TaxType: taxType,
    AccountCode: (product ? product.json['Revenue Account Code'] : '') || '200',
    LineAmount: lineSubtotal,
  });
}

const total = subtotal + totalVat;

return {
  json: {
    ...invoice,
    processedLineItems: processedItems,
    lineItemsJson: JSON.stringify(xeroLineItems),
    subtotal: Math.round(subtotal * 100) / 100,
    vatAmount: Math.round(totalVat * 100) / 100,
    total: Math.round(total * 100) / 100,
    currency: 'ZAR',
  }
};

const invoice = $input.first().json;
const prefix = $('System Config').first().json.invoicePrefix || 'AVM';
const timestamp = Date.now().toString().slice(-6);
const invoiceNumber = `${prefix}-${timestamp}`;

return {
  json: {
    ...invoice,
    invoiceNumber: invoiceNumber,
  }
};

const inv = $input.first().json;
const dueDate = new Date(inv.dueDate || inv['Due Date']);

if (isNaN(dueDate.getTime())) {
  return { json: { ...inv, nextReminderDate: null } };
}

// T-3: 3 days before due
const tMinus3 = new Date(dueDate);
tMinus3.setDate(tMinus3.getDate() - 3);

const today = new Date();
today.setHours(0, 0, 0, 0);

// Find the next reminder date that's in the future
const reminderDates = [
  { days: -3, date: tMinus3 },
  { days: 0, date: new Date(dueDate) },
  { days: 3, date: new Date(dueDate.getTime() + 3 * 86400000) },
  { days: 7, date: new Date(dueDate.getTime() + 7 * 86400000) },
  { days: 14, date: new Date(dueDate.getTime() + 14 * 86400000) },
];

let nextReminder = null;
for (const r of reminderDates) {
  if (r.date >= today) {
    nextReminder = r.date.toISOString().split('T')[0];
    break;
  }
}

return {
  json: {
    ...inv,
    nextReminderDate: nextReminder,
    reminderCount: 0,
  }
};

const items = $input.all();
const config = $('System Config').first().json;

let totalInvoiced = 0;
let invoiceCount = 0;
let pendingApproval = 0;
let sentCount = 0;
const summaryLines = [];

for (const item of items) {
  const inv = item.json;
  if (inv && inv.invoiceNumber) {
    invoiceCount++;
    totalInvoiced += inv.total || 0;
    if (inv.Status === 'Pending Approval') {
      pendingApproval++;
    } else {
      sentCount++;
    }
    summaryLines.push(`${inv.invoiceNumber} - ${inv.customerName || 'Unknown'} - R ${(inv.total || 0).toFixed(2)} [${inv.Status || 'Processed'}]`);
  }
}

const summaryHtml = `<h2>Invoice Processing Summary</h2>
<p><strong>Date:</strong> ${config.todayDate}</p>
<p><strong>Total Invoices Processed:</strong> ${invoiceCount}</p>
<p><strong>Sent:</strong> ${sentCount} | <strong>Pending Approval:</strong> ${pendingApproval}</p>
<p><strong>Total Invoiced:</strong> R ${totalInvoiced.toFixed(2)}</p>
<hr>
<ul>${summaryLines.map(l => '<li>' + l + '</li>').join('')}</ul>`;

return {
  json: {
    summaryHtml: summaryHtml,
    invoiceCount: invoiceCount,
    totalInvoiced: totalInvoiced,
    sentCount: sentCount,
    pendingApproval: pendingApproval,
  }
};

const invoice = $input.first().json;
const customer = $('Lookup Customer').first().json;

const today = new Date();
today.setHours(0, 0, 0, 0);

const dueDate = new Date(invoice['Due Date']);
dueDate.setHours(0, 0, 0, 0);

const daysDiff = Math.floor((today - dueDate) / (1000 * 60 * 60 * 24));
const nextReminder = invoice['Next Reminder Date'] ? new Date(invoice['Next Reminder Date']) : null;

let reminderStage = 'no_action';
let reminderTone = '';

if (nextReminder && nextReminder > today) {
  reminderStage = 'no_action';
} else if (daysDiff <= -3 && daysDiff > -4) {
  reminderStage = 't_minus_3';
  reminderTone = 'friendly';
} else if (daysDiff >= -1 && daysDiff <= 1) {
  reminderStage = 'due_date';
  reminderTone = 'reminder';
} else if (daysDiff >= 2 && daysDiff <= 5) {
  reminderStage = 't_plus_3';
  reminderTone = 'firm';
} else if (daysDiff >= 6 && daysDiff <= 10) {
  reminderStage = 't_plus_7';
  reminderTone = 'collections';
} else if (daysDiff >= 11) {
  reminderStage = 't_plus_14';
  reminderTone = 'escalation';
}

// If already reminded at this stage, skip
const reminderCount = parseInt(invoice['Reminder Count'] || '0');

return {
  json: {
    ...invoice,
    customerName: customer['Legal Name'] || customer['Trading Name'] || '',
    customerEmail: customer['Email'] || '',
    customerPhone: customer['Phone'] || '',
    preferredChannel: customer['Preferred Channel'] || 'Email',
    riskFlag: customer['Risk Flag'] || 'Low',
    reminderStage: reminderStage,
    reminderTone: reminderTone,
    daysPastDue: daysDiff,
    dueDate: invoice['Due Date'],
    invoiceNumber: invoice['Invoice Number'],
    total: invoice['Total'],
    balanceDue: invoice['Balance Due'] || invoice['Total'],
    reminderCount: reminderCount,
  }
};

const input = $input.first().json;
const body = input.body || input;

const invoiceNumber = body.invoice_number || body.invoiceNumber || '';
const reason = body.reason || body.dispute_reason || 'Not specified';
const details = body.details || body.description || '';
const customerName = body.customer_name || body.customerName || '';
const customerEmail = body.customer_email || body.customerEmail || '';

if (!invoiceNumber) {
  throw new Error('Missing required field: invoice_number');
}

// Assign dispute owner based on reason category
let disputeOwner = 'accounts@anyvisionmedia.com';
let priority = 'Normal';

const reasonLower = reason.toLowerCase();
if (reasonLower.includes('overcharge') || reasonLower.includes('incorrect amount')) {
  disputeOwner = 'accounts@anyvisionmedia.com';
  priority = 'High';
} else if (reasonLower.includes('service') || reasonLower.includes('quality')) {
  disputeOwner = 'ian@anyvisionmedia.com';
  priority = 'High';
} else if (reasonLower.includes('duplicate')) {
  disputeOwner = 'accounts@anyvisionmedia.com';
  priority = 'Normal';
} else if (reasonLower.includes('not received') || reasonLower.includes('wrong')) {
  disputeOwner = 'accounts@anyvisionmedia.com';
  priority = 'High';
}

return {
  json: {
    invoiceNumber: invoiceNumber,
    disputeReason: reason,
    disputeDetails: details,
    customerName: customerName,
    customerEmail: customerEmail,
    disputeOwner: disputeOwner,
    priority: priority,
    disputeDate: new Date().toISOString().split('T')[0],
    status: 'Disputed',
  }
};

const allItems = $input.all();

let totalProcessed = 0;
let remindersSent = 0;
let escalations = 0;
let skipped = 0;
const summaryLines = [];

for (const item of allItems) {
  totalProcessed++;
  const stage = item.json.reminderStage || item.json.lastReminderStage || 'unknown';
  const inv = item.json.invoiceNumber || item.json['Invoice Number'] || 'N/A';

  if (stage === 'no_action' || stage === 'unknown') {
    skipped++;
  } else {
    remindersSent++;
    if (stage === 't_plus_14') escalations++;
    summaryLines.push(`${inv}: ${stage}`);
  }
}

const summary = [
  `Collections Run Complete - ${new Date().toISOString().split('T')[0]}`,
  `Total Invoices Processed: ${totalProcessed}`,
  `Reminders Sent: ${remindersSent}`,
  `Escalations: ${escalations}`,
  `Skipped (no action): ${skipped}`,
  '',
  'Details:',
  ...summaryLines,
].join('\n');

return {
  json: {
    summary: summary,
    totalProcessed: totalProcessed,
    remindersSent: remindersSent,
    escalations: escalations,
    skipped: skipped,
    completedAt: new Date().toISOString(),
  }
};

const input = $input.first().json;
const body = input.body || input;

// PayFast ITN signature validation
// 1. Get all posted params except signature
const params = {};
const skipFields = ['signature'];
for (const [key, value] of Object.entries(body)) {
  if (!skipFields.includes(key) && value !== '') {
    params[key] = value;
  }
}

// 2. Sort alphabetically and URL-encode
const sortedKeys = Object.keys(params).sort();
const paramString = sortedKeys.map(key => 
  `${key}=${encodeURIComponent(params[key]).replace(/%20/g, '+')}`
).join('&');

// 3. Add passphrase if set (from env or System Config)
const passphrase = ''; // Set via PayFast merchant config
const stringToHash = passphrase ? `${paramString}&passphrase=${encodeURIComponent(passphrase)}` : paramString;

// 4. MD5 hash
const crypto = require('crypto');
const calculatedSignature = crypto.createHash('md5').update(stringToHash).digest('hex');

const isValid = calculatedSignature === body.signature;

return {
  json: {
    ...body,
    isValid: isValid,
    calculatedSignature: calculatedSignature,
    receivedSignature: body.signature || '',
    paymentStatus: body.payment_status,
    amount: parseFloat(body.amount_gross || body.amount_net || '0'),
    reference: body.m_payment_id || body.pf_payment_id || '',
  }
};

const input = $input.first().json;
const body = input.body || input;

// Check if this came from System Config (schedule/manual trigger) with no actual payment data
// System Config sets todayDate, companyName, etc. but no payment fields
if (!body.body && !body.amount && !body.payment_intent && !body.m_payment_id
    && !body.pf_payment_id && !body.amount_gross && !body.type
    && (body.todayDate || body.companyName)) {
  // No payment data available - this was a scheduled/manual trigger without webhook data
  // TODO: In production, this path should call the Xero Bank Transactions API
  // to fetch recent bank transactions before normalizing
  return [{json: {_noPayment: true, reason: 'No payment data - bank import not yet configured'}}];
}

let normalized;

// Detect source
if (body.type === 'payment_intent.succeeded' || body.object === 'event') {
  // Stripe webhook
  const pi = body.data ? body.data.object : body;
  normalized = {
    amount: (pi.amount || 0) / 100, // Stripe uses cents
    currency: (pi.currency || 'zar').toUpperCase(),
    reference: pi.metadata ? (pi.metadata.invoice_number || pi.id) : pi.id,
    method: 'Stripe',
    gatewayTransactionId: pi.id,
    payerEmail: pi.receipt_email || (pi.charges ? pi.charges.data[0].billing_details.email : ''),
    payerName: pi.metadata ? pi.metadata.customer_name : '',
    dateReceived: new Date().toISOString().split('T')[0],
  };
} else if (body.pf_payment_id || body.payment_status) {
  // PayFast ITN
  normalized = {
    amount: parseFloat(body.amount_gross || '0'),
    currency: 'ZAR',
    reference: body.m_payment_id || body.custom_str1 || '',
    method: 'PayFast',
    gatewayTransactionId: body.pf_payment_id,
    payerEmail: body.email_address || '',
    payerName: `${body.name_first || ''} ${body.name_last || ''}`.trim(),
    dateReceived: new Date().toISOString().split('T')[0],
  };
} else {
  // Manual/bank import
  normalized = {
    amount: parseFloat(body.amount || '0'),
    currency: body.currency || 'ZAR',
    reference: body.reference || body.description || '',
    method: body.method || 'EFT',
    gatewayTransactionId: body.transaction_id || '',
    payerEmail: body.payer_email || '',
    payerName: body.payer_name || '',
    dateReceived: body.date || new Date().toISOString().split('T')[0],
  };
}

normalized.paymentId = `PAY-${Date.now()}`;

return { json: normalized };

const payment = $('Create Payment Record').first().json;
const invoices = $input.all().map(i => i.json ? i : {json: i});
const reference = (payment.reference || '').toUpperCase();
const amount = payment.amount;

let matchedInvoice = null;
let matchType = 'none';

// 1. Try exact invoice number match in reference
for (const inv of invoices) {
  const invNum = (inv.json['Invoice Number'] || '').toUpperCase();
  if (invNum && reference.includes(invNum)) {
    const invTotal = parseFloat(inv.json['Balance Due'] || inv.json['Total'] || 0);
    if (Math.abs(amount - invTotal) < 0.50) {
      matchedInvoice = inv.json;
      matchType = 'exact';
      break;
    } else {
      matchedInvoice = inv.json;
      matchType = 'reference_match_amount_differs';
      break;
    }
  }
}

// 2. If no reference match, try exact amount match (only if unique)
if (!matchedInvoice) {
  const amountMatches = invoices.filter(inv => {
    const invTotal = parseFloat(inv.json['Balance Due'] || inv.json['Total'] || 0);
    return Math.abs(amount - invTotal) < 0.50;
  });
  if (amountMatches.length === 1) {
    matchedInvoice = amountMatches[0].json;
    matchType = 'amount_match';
  }
}

return {
  json: {
    ...payment,
    matchFound: !!matchedInvoice,
    matchType: matchType,
    matchedInvoiceId: matchedInvoice ? matchedInvoice['Invoice ID'] : null,
    matchedInvoiceNumber: matchedInvoice ? matchedInvoice['Invoice Number'] : null,
    matchedCustomerId: matchedInvoice ? matchedInvoice['Customer ID'] : null,
    matchedCustomerName: matchedInvoice ? matchedInvoice['Customer Name'] : null,
    matchedInvoiceTotal: matchedInvoice ? parseFloat(matchedInvoice['Total'] || 0) : 0,
    matchedBalanceDue: matchedInvoice ? parseFloat(matchedInvoice['Balance Due'] || matchedInvoice['Total'] || 0) : 0,
    openInvoiceCount: invoices.length,
    openInvoiceSummary: invoices.slice(0, 10).map(i => ({
      id: i.json['Invoice ID'],
      number: i.json['Invoice Number'],
      customer: i.json['Customer Name'],
      total: i.json['Total'],
      balance: i.json['Balance Due'],
    })),
  }
};

