const input = $input.first().json;
const payment = $('Exact Match Attempt').first().json;

let match;
try {
  const content = input.choices[0].message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  match = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch(e) {
  match = { matched_invoice_id: null, confidence: 0, reasoning: 'Failed to parse AI response' };
}

// Look up matched invoice details for balance/total fields
const matchedInvoiceId = match.matched_invoice_id || null;
const matchedInvoiceNumber = match.matched_invoice_number || null;
let matchedBalanceDue = 0;
let matchedInvoiceTotal = 0;
let matchedCustomerId = null;
let matchedCustomerName = null;

if (matchedInvoiceId || matchedInvoiceNumber) {
  const invoices = $('Search Open Invoices').all();
  const matchedInvoice = invoices.find(i =>
    i.json['Invoice ID'] === matchedInvoiceId || i.json['Invoice Number'] === matchedInvoiceNumber
  );
  if (matchedInvoice) {
    matchedBalanceDue = parseFloat(matchedInvoice.json['Balance Due'] || matchedInvoice.json['Total'] || 0);
    matchedInvoiceTotal = parseFloat(matchedInvoice.json['Total'] || 0);
    matchedCustomerId = matchedInvoice.json['Customer ID'] || null;
    matchedCustomerName = matchedInvoice.json['Customer Name'] || null;
  }
}

return {
  json: {
    ...payment,
    matchFound: match.confidence > 0.5,
    matchType: 'ai_fuzzy',
    matchConfidence: match.confidence,
    matchReasoning: match.reasoning || '',
    matchedInvoiceId: matchedInvoiceId,
    matchedInvoiceNumber: matchedInvoiceNumber,
    matchedBalanceDue: matchedBalanceDue,
    matchedInvoiceTotal: matchedInvoiceTotal,
    matchedCustomerId: matchedCustomerId,
    matchedCustomerName: matchedCustomerName,
  }
};

const data = $input.first().json;
const paymentAmount = data.amount;
const balanceDue = data.matchedBalanceDue;

let status, newBalance, newAmountPaid, invoiceStatus;

if (Math.abs(paymentAmount - balanceDue) < 0.50) {
  status = 'exact';
  newBalance = 0;
  newAmountPaid = data.matchedInvoiceTotal;
  invoiceStatus = 'Paid';
} else if (paymentAmount < balanceDue) {
  status = 'partial';
  newBalance = Math.round((balanceDue - paymentAmount) * 100) / 100;
  newAmountPaid = Math.round((data.matchedInvoiceTotal - newBalance) * 100) / 100;
  invoiceStatus = 'Partial';
} else {
  status = 'overpayment';
  newBalance = 0;
  newAmountPaid = data.matchedInvoiceTotal;
  invoiceStatus = 'Paid';
}

return {
  json: {
    ...data,
    paymentType: status,
    newBalanceDue: newBalance,
    newAmountPaid: newAmountPaid,
    overpaymentAmount: status === 'overpayment' ? Math.round((paymentAmount - balanceDue) * 100) / 100 : 0,
    invoiceStatus: invoiceStatus,
  }
};

const email = $input.first().json;

const sender = email.from || email.sender || '';
const subject = email.subject || '';
const body = (email.text || email.snippet || '').substring(0, 3000);
const attachments = email.attachments || [];

return {
  json: {
    emailId: email.id,
    sender: sender,
    subject: subject,
    bodyText: body,
    hasAttachment: attachments.length > 0,
    attachmentCount: attachments.length,
    receivedAt: email.date || new Date().toISOString(),
    extractionInput: `From: ${sender}\nSubject: ${subject}\n\n${body}`,
  }
};

const input = $input.first().json;
const emailData = $('Extract Email Data').first().json;

let extracted;
try {
  const content = input.choices[0].message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  extracted = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
} catch(e) {
  extracted = {
    supplier_name: emailData.sender.split('<')[0].trim() || 'Unknown',
    invoice_number: 'UNKNOWN',
    bill_date: new Date().toISOString().split('T')[0],
    due_date: null,
    subtotal: 0,
    vat_amount: 0,
    total_amount: 0,
    confidence: 0,
  };
}

// Calculate due date if missing
if (!extracted.due_date && extracted.bill_date) {
  const billDate = new Date(extracted.bill_date);
  billDate.setDate(billDate.getDate() + 30);
  extracted.due_date = billDate.toISOString().split('T')[0];
}

// Validate/recalculate amounts
if (extracted.total_amount && !extracted.subtotal) {
  extracted.subtotal = Math.round(extracted.total_amount / 1.15 * 100) / 100;
  extracted.vat_amount = Math.round((extracted.total_amount - extracted.subtotal) * 100) / 100;
}

return {
  json: {
    ...emailData,
    ...extracted,
    billId: `BILL-${Date.now()}`,
  }
};

const extraction = $('Parse Extraction').first().json;
const supplierInput = $input.first().json;

// Determine if supplier came from lookup or create
const supplierId = supplierInput.id || supplierInput['Supplier ID'] || `SUP-${Date.now()}`;
const supplierName = supplierInput['Supplier Name'] || extraction.supplier_name;
const supplierPaymentTerms = supplierInput['Default Payment Terms'] || '30 days';
const isKnownSupplier = !!supplierInput['Supplier Name'];

return {
  json: {
    ...extraction,
    supplierId: supplierId,
    supplierName: supplierName,
    supplierPaymentTerms: supplierPaymentTerms,
    isKnownSupplier: isKnownSupplier,
    supplierAirtableId: supplierInput.id || null,
  }
};

