const input = $input.first().json;
const prevData = $('Merge Supplier Data').first().json;

let category = 'Other';
let categoryConfidence = 0;
let categoryReasoning = '';

try {
  const content = input.choices[0].message.content;
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  const parsed = JSON.parse(jsonMatch ? jsonMatch[0] : cleaned);
  category = parsed.category || 'Other';
  categoryConfidence = parsed.confidence || 0;
  categoryReasoning = parsed.reasoning || '';
} catch(e) {
  category = 'Other';
  categoryConfidence = 0;
  categoryReasoning = 'AI parsing failed, defaulting to Other';
}

return {
  json: {
    ...prevData,
    expenseCategory: category,
    categoryConfidence: categoryConfidence,
    categoryReasoning: categoryReasoning,
  }
};

const billData = $('Parse Extraction').first().json;
const supplierData = $('Merge Supplier Data').first().json;
const data = $input.first().json;
const dueDate = billData.due_date;
const paymentTerms = supplierData.paymentTerms || supplierData['Payment Terms'] || '30';
const supplierTerms = supplierData.supplierPaymentTerms || paymentTerms + ' days';

let paymentDate;
const dueDateParsed = new Date(dueDate || data['Due Date']);

if (isNaN(dueDateParsed.getTime())) {
  const today = new Date();
  today.setDate(today.getDate() + 30);
  paymentDate = today.toISOString().split('T')[0];
} else {
  paymentDate = dueDateParsed.toISOString().split('T')[0];
}

return {
  json: {
    ...data,
    scheduledPaymentDate: paymentDate,
  }
};

const items = $input.all();

let totalBills = 0;
let totalAmount = 0;
let autoApproved = 0;
let pendingApproval = 0;
let suppliers = new Set();
let categories = {};

for (const item of items) {
  const data = item.json;
  if (data.billId || data['Bill ID']) {
    totalBills++;
    totalAmount += parseFloat(data.total_amount || data['Total Amount'] || 0);
    suppliers.add(data.supplierName || data['Supplier Name'] || 'Unknown');
    const cat = data.expenseCategory || data['Expense Category'] || 'Other';
    categories[cat] = (categories[cat] || 0) + 1;
    if (data.approvalStatus === 'Auto Approved' || data['Approval Status'] === 'Auto Approved') {
      autoApproved++;
    } else {
      pendingApproval++;
    }
  }
}

return {
  json: {
    summary: {
      totalBills: totalBills,
      totalAmount: Math.round(totalAmount * 100) / 100,
      autoApproved: autoApproved,
      pendingApproval: pendingApproval,
      uniqueSuppliers: suppliers.size,
      categories: categories,
      processedAt: new Date().toISOString(),
    }
  }
};

const today = new Date();
const year = today.getFullYear();
const month = today.getMonth();
const lastDay = new Date(year, month + 1, 0);
let lastBusinessDay = new Date(lastDay);

while (lastBusinessDay.getDay() === 0 || lastBusinessDay.getDay() === 6) {
  lastBusinessDay.setDate(lastBusinessDay.getDate() - 1);
}

// If triggered manually, always proceed (bypass date check)
const isManual = $('Manual Trigger').isExecuted;
const isLastBusinessDay = isManual || today.getDate() === lastBusinessDay.getDate();
const monthName = today.toLocaleString('en-ZA', { month: 'long', year: 'numeric' });

return {
  json: {
    isLastBusinessDay: isLastBusinessDay,
    todayDate: today.toISOString().split('T')[0],
    monthName: monthName,
    lastBusinessDay: lastBusinessDay.toISOString().split('T')[0],
    monthStart: `${year}-${String(month + 1).padStart(2, '0')}-01`,
    monthEnd: lastDay.toISOString().split('T')[0],
  }
};

const invoices = $('Read All Open Invoices').all();
const today = new Date();
const buckets = { current: [], days_31_60: [], days_61_90: [], days_91_120: [], days_120_plus: [] };
let totalAR = 0;

for (const inv of invoices) {
  const dueDate = new Date(inv.json['Due Date']);
  const daysPast = Math.floor((today - dueDate) / 86400000);
  const balance = parseFloat(inv.json['Balance Due'] || inv.json['Total'] || 0);
  totalAR += balance;

  const record = { invoiceNumber: inv.json['Invoice Number'], customer: inv.json['Customer Name'], balance, daysPast };

  if (daysPast <= 30) buckets.current.push(record);
  else if (daysPast <= 60) buckets.days_31_60.push(record);
  else if (daysPast <= 90) buckets.days_61_90.push(record);
  else if (daysPast <= 120) buckets.days_91_120.push(record);
  else buckets.days_120_plus.push(record);
}

const summary = {
  current: buckets.current.reduce((s, r) => s + r.balance, 0),
  days_31_60: buckets.days_31_60.reduce((s, r) => s + r.balance, 0),
  days_61_90: buckets.days_61_90.reduce((s, r) => s + r.balance, 0),
  days_91_120: buckets.days_91_120.reduce((s, r) => s + r.balance, 0),
  days_120_plus: buckets.days_120_plus.reduce((s, r) => s + r.balance, 0),
};

return { json: { agedReceivables: buckets, arSummary: summary, totalAR, invoiceCount: invoices.length } };

const bills = $('Read All Open Bills').all();
const today = new Date();
const buckets = { current: [], days_31_60: [], days_61_90: [], days_91_120: [], days_120_plus: [] };
let totalAP = 0;

for (const bill of bills) {
  const dueDate = new Date(bill.json['Due Date']);
  const daysPast = Math.floor((today - dueDate) / 86400000);
  const balance = parseFloat(bill.json['Balance Due'] || bill.json['Total'] || 0);
  totalAP += balance;

  const record = { billNumber: bill.json['Bill Number'], supplier: bill.json['Supplier Name'], balance, daysPast };

  if (daysPast <= 30) buckets.current.push(record);
  else if (daysPast <= 60) buckets.days_31_60.push(record);
  else if (daysPast <= 90) buckets.days_61_90.push(record);
  else if (daysPast <= 120) buckets.days_91_120.push(record);
  else buckets.days_120_plus.push(record);
}

const summary = {
  current: buckets.current.reduce((s, r) => s + r.balance, 0),
  days_31_60: buckets.days_31_60.reduce((s, r) => s + r.balance, 0),
  days_61_90: buckets.days_61_90.reduce((s, r) => s + r.balance, 0),
  days_91_120: buckets.days_91_120.reduce((s, r) => s + r.balance, 0),
  days_120_plus: buckets.days_120_plus.reduce((s, r) => s + r.balance, 0),
};

return { json: { agedPayables: buckets, apSummary: summary, totalAP, billCount: bills.length } };

const dateInfo = $('Check Last Business Day').first().json;
const monthStart = new Date(dateInfo.monthStart);
const monthEnd = new Date(dateInfo.monthEnd + 'T23:59:59');

// Filter payments and audit logs to current month
const allPayments = $('Read Payments This Month').all();
const payments = allPayments.filter(p => {
  const d = new Date(p.json['Date Received']);
  return !isNaN(d.getTime()) && d >= monthStart && d <= monthEnd;
});
const allLogs = $('Read Audit Log This Month').all();
const auditLogs = allLogs.filter(l => {
  const d = new Date(l.json['Created At']);
  return !isNaN(d.getTime()) && d >= monthStart && d <= monthEnd;
});

const invoices = $('Read All Open Invoices').all();
const arData = $('Build Aged Receivables').first().json;
const apData = $('Build Aged Payables').first().json;

const discrepancies = [];

// Check 1: Payments without matching invoices
for (const pmt of payments) {
  const invoiceRef = pmt.json['Invoice Number'] || pmt.json['Reference'] || '';
  if (invoiceRef) {
    const matchingInvoice = invoices.find(inv => 
      inv.json['Invoice Number'] === invoiceRef
    );
    if (!matchingInvoice) {
      discrepancies.push({
        type: 'ORPHANED_PAYMENT',
        description: `Payment ${pmt.json['Payment ID'] || 'unknown'} references invoice ${invoiceRef} which was not found in open invoices`,
        amount: parseFloat(pmt.json['Amount'] || 0),
        reference: invoiceRef,
      });
    }
  }
}

// Check 2: Invoices overdue by 120+ days (potential write-offs)
const overdue120 = arData.agedReceivables.days_120_plus || [];
for (const inv of overdue120) {
  discrepancies.push({
    type: 'OVERDUE_120_PLUS',
    description: `Invoice ${inv.invoiceNumber} for ${inv.customer} is ${inv.daysPast} days overdue - consider write-off`,
    amount: inv.balance,
    reference: inv.invoiceNumber,
  });
}

// Check 3: Bills overdue by 120+ days
const overdueAP120 = apData.agedPayables.days_120_plus || [];
for (const bill of overdueAP120) {
  discrepancies.push({
    type: 'OVERDUE_BILL_120_PLUS',
    description: `Bill ${bill.billNumber} for ${bill.supplier} is ${bill.daysPast} days overdue - urgent payment required`,
    amount: bill.balance,
    reference: bill.billNumber,
  });
}

// Build summary stats
const totalPaymentsReceived = payments.reduce((s, p) => s + parseFloat(p.json['Amount'] || 0), 0);
const netPosition = arData.totalAR - apData.totalAP;

return {
  json: {
    hasDiscrepancies: discrepancies.length > 0,
    discrepancyCount: discrepancies.length,
    discrepancies: discrepancies,
    totalPaymentsReceived: totalPaymentsReceived,
    paymentCount: payments.length,
    totalAR: arData.totalAR,
    totalAP: apData.totalAP,
    netPosition: netPosition,
    arSummary: arData.arSummary,
    apSummary: apData.apSummary,
    invoiceCount: arData.invoiceCount,
    billCount: apData.billCount,
    auditLogCount: auditLogs.length,
    agedReceivables: arData.agedReceivables,
    agedPayables: apData.agedPayables,
  }
};

