if (dueAt) {
  const dueDate = new Date(dueAt);
  if (!isNaN(dueDate.getTime())) {
    isOverdue = now > dueDate;
    daysPastDue = isOverdue ? Math.floor((now - dueDate) / 86400000) : 0;
  }
}

// Only escalate if not already escalated
const shouldEscalate = isOverdue && task['Status'] !== 'Escalated';

return {
