    airtableRecordId: task['id'] || '',
  }
};

const query = $input.first().json.query || $input.first().json;
const token = query.token || '';
const action = query.action || '';

if (!token || !action) {
  return { json: { isValid: false, error: 'Missing token or action parameter' } };
}

if (!['approve', 'reject'].includes(action)) {
  return { json: { isValid: false, error: 'Invalid action. Must be approve or reject.' } };
}

return { json: { isValid: true, token, action } };

const task = $input.first().json;
const action = $('Process Webhook Approval').first().json.action;
const token = $('Process Webhook Approval').first().json.token;

if (!task || !task['Type']) {
  return {
    json: {
      error: 'Task not found for the provided token',
      token: token,
      action: action,
      routeKey: 'not_found',
    }
  };
}

const taskType = task['Type'] || '';
let routeKey = 'reject';

if (action === 'approve') {
  if (taskType.toLowerCase().includes('invoice')) {
    routeKey = 'approve_invoice';
  } else if (taskType.toLowerCase().includes('bill')) {
    routeKey = 'approve_bill';
  } else {
    routeKey = 'approve_invoice'; // default approval
  }
} else {
  routeKey = 'reject';
}

// Determine related record ID and table
let relatedRecordId = '';
let relatedTable = 'Invoices';
if (routeKey === 'approve_bill') {
  relatedRecordId = task['Related Record ID'] || '';
  relatedTable = 'Supplier Bills';
} else {
  relatedRecordId = task['Related Record ID'] || '';
  relatedTable = 'Invoices';
}

return {
  json: {
    ...task,
    action: action,
    token: token,
    routeKey: routeKey,
    taskId: task['Task ID'] || '',
    airtableRecordId: task['id'] || '',
    relatedInvoice: task['Related Invoice'] || '',
    relatedBill: task['Related Bill'] || '',
    relatedRecordId: relatedRecordId,
    relatedTable: relatedTable,
    taskDescription: task['Description'] || '',
  }
};

const data = $input.first().json;
const action = data.action;
const isApprove = action === 'approve';

// Determine new status for the related record
let newStatus = 'Rejected';
if (isApprove) {
  newStatus = 'Approved';
}

// Build the response HTML
const html = `<!DOCTYPE html><html><head><meta charset="utf-8">
