h1{color:${isApprove ? '#22c55e' : '#ef4444'};margin:0 0 8px;}
p{color:#666;margin:0;}</style></head>
<body><div class="card">
<div class="icon">${isApprove ? '&#10004;' : '&#10006;'}</div>
<h1>${isApprove ? 'Approved' : 'Rejected'}</h1>
