<p style="margin-top:16px;font-size:12px;color:#999;">AnyVision Media Accounting</p>
</div></body></html>`;

return {
  json: {
    ...data,
    newStatus: newStatus,
    responseHtml: html,
    processedAt: new Date().toISOString(),
  }
};
